<span class="line"><span style="color:#A6E3A1;">        agent </span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">fix the tests</span><span style="color:#F5C2E7;">\\&quot;</span><span style="color:#A6E3A1;">          Run with initial prompt</span><span style="color:#F5C2E7;">\\n</span><span style="color:#A6E3A1;">  \\</span></span>
