<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#89B4FA;font-style:italic;"> handle_command</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">command</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">cli</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#9399B2;">;</span></span>
