<span class="line"><span style="color:#F9E2AF;font-style:italic;">        ShellType</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Bash</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Shell</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Bash</span><span style="color:#9399B2;">,</span></span>
